module RefModule(input signed [16:0] serIn , input [16:0] init_value , input en, input clk, input rst , input init , output reg signed [16:0] Q);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @ (posedge clk, posedge rst or posedge dbg_halt) begin

    if(rst) Q <= 17'b0;
    else if(en) Q <= serIn;
    else if(init) Q <= init_value;
  end
endmodule
